-- Enrichment marathon batch: OpenOLAT, OpenOlitor, OpenPhone, OpenProject, OpenReader, OpenRemote, OpenReplay, OpenRouter

-- ── OpenOLAT ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenOLAT is an open-source learning management system (LMS) built by frentix GmbH for universities, enterprises, and public institutions to deliver online courses, assessments, and certifications.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted plans from frentix on request$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees (frentix GmbH)$q$, company_size),
  headquarters = COALESCE($q$Zurich, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Italian$q$, $q$Spanish$q$, $q$and 15+ additional languages$q$]::text[],
  seo_title = COALESCE($q$OpenOLAT Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenOLAT review 2026: explore this open-source LMS's course authoring, testing engine, video tools, pricing, hosting options, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenOLAT (Open Online Learning And Training) is an open-source learning management system originally forked in 2011 from the University of Zurich's OLAT project by frentix GmbH, a Zurich, Switzerland-based software company founded in 2006 by Florian Gnaegi, one of OLAT's original creators. OpenOLAT is used by universities, vocational schools, enterprises, and public-sector organizations across German-speaking Europe and beyond to run online courses, blended learning programs, certifications, and large-scale examinations. Its core differentiator is a fully independent, high-stakes testing environment capable of running proctored, timed, randomized exams alongside self-assessment quizzes, which has made it popular with universities and professional certification bodies that need exam-grade reliability rather than a lightweight quiz plugin. Other standout capabilities include integrated BigBlueButton video conferencing, YouTube-style video hosting with embedded interactive questions, document collaboration via OnlyOffice, LDAP, Active Directory, OAuth2 and Shibboleth single sign-on for institutional identity systems, and a course editor supporting SCORM, xAPI, and IMS QTI content. The interface and course content can be delivered in around 20 languages, reflecting adoption across multilingual European institutions. OpenOLAT is free to download, install, and self-host under its open-source license; organizations that prefer not to run their own servers can instead pay frentix for managed hosting, technical support, training, and customization, with pricing quoted individually per institution rather than published as fixed tiers. This dual model, a free open-source core plus optional paid hosting and services, mirrors other institution-grade open-source LMS platforms. Its closest competitors are Moodle, the dominant open-source LMS globally, plus commercial platforms like Canvas, Blackboard Learn, and ILIAS, another German-origin open-source LMS. Compared with Moodle, OpenOLAT is often described by IT teams as more lightweight to administer and faster out of the box, with a more opinionated, less plugin-dependent architecture, while Moodle has a much larger global plugin ecosystem. OpenOLAT's target audience is IT and e-learning teams at universities, corporate training departments, and government agencies that need a self-hostable, data-sovereign LMS, particularly organizations in Switzerland and Germany subject to strict data residency requirements. Because it can be fully self-hosted in the EU or Switzerland, it is frequently chosen by institutions that cannot use US-hosted SaaS LMS platforms for compliance reasons. frentix, the company behind OpenOLAT, remains a small team of roughly a dozen to a few dozen employees, funding development primarily through hosting and support contracts rather than venture capital.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a2781d6d-0be8-4b83-b404-3a5b91254b15';

