-- ── OpenOlitor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenOlitor is a free, open-source AGPL-licensed platform that helps Community Supported Agriculture (CSA) groups manage members, share planning, deliveries, invoicing, and communication.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); new features are community co-financed$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$10+ community contributors (no formal company; led by Tegonal GmbH, Bern)$q$, company_size),
  headquarters = COALESCE($q$Bern, Switzerland (community-run project with contributors across Switzerland, Germany, Austria, and Italy)$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$French$q$, $q$Italian$q$, $q$English$q$, $q$and 4 additional languages$q$]::text[],
  seo_title = COALESCE($q$OpenOlitor Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenOlitor review 2026: how this open-source AGPL platform helps CSA groups manage members, deliveries, invoicing and shares, plus pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenOlitor is a free, open-source software platform purpose-built for Community Supported Agriculture (CSA) organizations, the farm-to-consumer model in which members subscribe to a share of a farm's harvest in advance. The project originated in Switzerland around 2014, conceived to give CSA groups, known as 'Solidarische Landwirtschaft' in German-speaking Europe, a shared, non-proprietary alternative to spreadsheets and closed commercial tools. Its first fully-financed version cost roughly CHF 154,000 and was co-funded by Switzerland's Federal Office for Agriculture (FOAG), the Bern-based software cooperative Tegonal GmbH, the CSA association Verein soliTerre, and a number of participating farms. OpenOlitor is not run by a conventional company; instead it is maintained by an international, loosely-organized team of more than ten contributors based in Switzerland, Germany, Austria, and Italy, operating under a 'Community Supported Software' funding model where the CSAs that use the platform help finance new features they need, mirroring the CSA farming model itself. The software was released under the GPL v3 license until April 2018 and the AGPL v3 license since, keeping the full source code freely available on GitHub. Functionally, OpenOlitor covers the operational backbone of running a CSA: member and household management, harvest-share and subscription planning, delivery-point and route scheduling, absence and vacation handling, automated invoicing, and bulk email communication with members, all accessible through a multilingual web interface translated into eight languages. It is actively used by around fifteen CSA organizations across Switzerland and Germany, making it a niche but purpose-fit tool rather than a broad commercial product. There is no traditional subscription pricing: the software itself is free to self-host, though CSAs typically need technical help or a hosting arrangement, often coordinated through Tegonal GmbH or community volunteers, to deploy and maintain an instance, and larger feature requests are typically crowd-funded by the participating CSA groups. OpenOlitor's competitors are less other CSA-specific platforms and more generic farm-share or subscription-box management tools and manual spreadsheet or email workflows; within the CSA space specifically it is one of very few dedicated open-source options. Its target audience is small to mid-size CSA farms and food cooperatives, primarily in German- and French-speaking Europe, run by farmers or volunteer coordinators who value data ownership, low cost, and a tool designed specifically around share-based agriculture rather than generic e-commerce or CRM software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0070da27-b0bd-4679-add1-4cfaeb297161';

