-- ── OpenReader ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenReader is a free, open-source, self-hostable read-along document reader that turns EPUB, PDF, DOCX, TXT, and Markdown files into synchronized text-to-speech audio with word-level highlighting and audiobook export.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); usage costs depend on the chosen text-to-speech provider$q$, starting_price),
  founded_year = COALESCE(2025, founded_year),
  company_size = COALESCE($q$Solo developer (independent open-source project)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (independent open-source project, no registered company)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenReader Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenReader review 2026: this open-source read-along document reader's TTS features, formats supported, self-hosting, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenReader is a free, open-source read-along document reader created by independent developer Richard Roberson (GitHub handle richardr1126) and first published in January 2025. It is a self-hosted web application, not a company or funded startup, distributed under the MIT license from its GitHub repository (richardr1126/openreader) and demoed publicly at openreader.richardr.dev. The tool converts EPUB, PDF, DOCX, TXT, and Markdown documents into a synchronized read-along experience: it plays high-quality text-to-speech narration while highlighting the exact word being spoken in the original document layout, using ONNX Whisper-based alignment to keep highlighting accurate even in dense, multi-column PDFs. Users can choose between hosted text-to-speech providers, including OpenAI, Replicate, and DeepInfra, for convenience, or fully self-hosted, offline TTS engines such as Kokoro, KittenTTS, and Orpheus for privacy and zero per-use cost, giving it flexibility that few commercial read-aloud apps offer. The application also supports full audiobook export, letting users generate a downloadable narrated audio file from any supported document. It is designed to be deployed via Docker on standard amd64 or arm64 servers, storing files on SeaweedFS or any S3-compatible bucket and data in SQLite or Postgres, with built-in authentication and automatic database migrations on startup. As a solo-developer open-source project rather than a commercial product, OpenReader has no pricing plans, sales team, or service-level agreement; its several hundred GitHub stars and active commit history indicate a genuinely maintained, actively developed project rather than an abandoned repository. It is best suited to privacy-conscious individuals, accessibility advocates, and self-hosting enthusiasts who want a narrated, synchronized reading experience for their personal EPUB or PDF library without depending on a subscription audiobook or read-aloud service such as Speechify, NaturalReader, or Voice Dream Reader, and who are comfortable running their own Docker-based server or paying directly for their own text-to-speech API usage instead of a bundled subscription.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f47d23ca-0f56-4a32-b7b9-20cfb7465b77';

