-- ── OpenRemote ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenRemote is a 100% open-source IoT platform for asset management, automation, and data visualization, used by integrators and enterprises to build smart building, energy, and industrial IoT solutions.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); managed hosting and professional services quoted on request$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Eindhoven, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$OpenRemote Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenRemote review 2026: open-source IoT platform features, asset management, automation, pricing model, pros, cons and alternatives for integrators.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenRemote is a 100% open-source Internet of Things (IoT) platform originally founded in 2008 by Marc Fleury, the creator of the JBoss open-source Java application server, initially as a smart-home automation project. Around 2016 the company pivoted away from consumer smart-home products to focus on enterprise and OEM IoT device management, and it now operates as OpenRemote B.V., headquartered in Eindhoven, the Netherlands, with a US entity as well, remaining privately held and bootstrapped without external venture funding, financed instead by client contracts for customization, hosting, and support. The platform's core differentiator is that its entire stack, backend, rules engine, and management console, is released as genuinely open-source software on GitHub with no proprietary 'enterprise-only' fork, which sets it apart from most commercial IoT platforms that gate advanced features behind closed licenses. OpenRemote is built around an asset-centric data model: users define custom asset types, such as a building, a sensor, a vehicle, or a solar inverter, and track their attributes over time, with built-in protocol support for HTTP, MQTT, ModBus, KNX, Bluetooth, LoRaWAN, SNMP, Velbus, TCP, UDP, and serial connections, making it well-suited to bridging heterogeneous hardware in smart buildings, energy management, industrial IoT, fleet telematics, smart agriculture, and smart city deployments. Automation is handled through simple When-Then rules, a visual Flow Editor for data-processing pipelines, or Groovy scripting for complex logic, and every asset and attribute is automatically exposed through a unified REST API and WebSockets for integration with external systems. The platform includes a built-in dashboard builder for live and historical data visualization, map-based geofencing and location tracking, and multi-tenant realm isolation with enterprise-grade identity management powered by Keycloak (OAuth2/OpenID Connect). Because the software itself is free to download and self-host with no per-device or per-user licensing fees, OpenRemote's business model is services-based: the company earns revenue by providing professional configuration, custom integration development, and managed cloud hosting to system integrators and enterprises that would rather pay for expertise than build in-house. Its target audience is professional IoT integrators, OEMs, and enterprise facilities or energy teams managing complex, multi-protocol asset ecosystems, distinguishing it from consumer smart-home apps and positioning it closer to ThingsBoard and commercial platforms like Losant or Ubidots as points of comparison.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '86bb955c-8712-45a0-8f45-aeab54c99a6f';

