-- ── OpenReplay ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenReplay is an open-source, self-hostable session replay and product analytics platform that lets developers record and replay user sessions, debug errors, and analyze product usage without sending data to a third party.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted); managed Dedicated plan from $199/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenReplay Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenReplay review 2026: open-source session replay features, self-hosting, pricing plans, pros, cons, FAQs and top alternatives like LogRocket and Hotjar.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenReplay is an open-source session replay and product analytics platform built by Asayer, Inc., a company founded in 2018 by CEO Mehdi Osman and backed by Y Combinator's S19 batch. The company originally launched as Asayer, a closed-source SaaS session-replay tool, before pivoting the entire product to an open-source model in 2020 and rebranding as OpenReplay, a strategic shift aimed at differentiating from closed-source incumbents like FullStory, Hotjar, and LogRocket by letting engineering teams self-host the entire stack and keep user session data on their own infrastructure. Headquartered in Paris, France, the company has raised a modest $6 million-plus in funding from Y Combinator, Runa Capital, Expa, and Kima Ventures, positioning it as a lean, developer-focused alternative rather than a venture-scale growth story. OpenReplay's core product records everything a user does in a web or mobile application, clicks, scrolls, page navigation, network requests, console logs, JavaScript errors, and framework-level state such as Redux, Vuex, Pinia, and GraphQL queries, then reconstructs it as a pixel-accurate replay synchronized with over 40 performance metrics, letting engineering and product teams debug issues and understand user behavior side by side rather than relying on two separate tools. Additional capabilities include co-browsing for live customer support sessions, a lightweight bug and feedback capture tool called Spot, product analytics such as funnels, heatmaps, and user flows, and an MCP server for connecting session data to AI coding and debugging workflows. OpenReplay ships in three tiers: a fully free, self-hosted Open-Source edition where the customer manages their own infrastructure, scaling, and backups; a Dedicated managed-cloud tier starting around $199 per month, billed hourly at roughly $0.276 per hour, that runs in OpenReplay's cloud or the customer's own cloud (BYOC) with SSO/SAML and dedicated support; and a custom-quoted Enterprise tier for self-hosted deployments at scale with SAML/SCIM provisioning, audit logging, and multi-year contracts. This makes OpenReplay's core differentiator, versus LogRocket, FullStory, and Hotjar, its ability to be run entirely on a company's own servers for data-privacy or compliance reasons at zero licensing cost, which is particularly attractive to engineering-led teams, regulated industries, and companies outside the US that are wary of shipping user session data to a third-party SaaS vendor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f79eaac2-65bc-4cc5-9c8f-74c78142ea6b';

