-- ── OpenRouter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenRouter is a unified API gateway that lets developers access 400-plus large language models from providers like OpenAI, Anthropic, and Google through a single API with pay-as-you-go, usage-based pricing.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; pay-as-you-go usage billed at provider cost plus a 5.5% platform fee$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenRouter Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenRouter review 2026: unified LLM API features, 400+ model access, pay-as-you-go pricing, pros, cons, FAQs and alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenRouter is a unified API and routing layer for large language models, founded in 2023 by CEO Alex Atallah, previously co-founder and CEO of the NFT marketplace OpenSea, and headquartered in New York City. The company gives developers a single API endpoint and a single API key to access more than 400 AI models from over 70 providers, spanning OpenAI, Anthropic, Google, Meta's Llama, Mistral, DeepSeek, and many others, removing the need to integrate each provider's SDK, billing, and rate limits separately. Its core value proposition is reliability and choice: OpenRouter automatically routes requests to the best-available provider for a given model, falls back to alternate providers during outages, and lets developers compare pricing, latency, and throughput across providers for the same model in real time, which has made it a default infrastructure layer for AI startups and hobbyist developers who want provider flexibility without vendor lock-in. OpenRouter raised roughly $40 million in early funding, a $12.5 million seed round led by Andreessen Horowitz and a $28 million Series A led by Menlo Ventures in April 2025, before raising a much larger $113 million Series B led by CapitalG, Alphabet's growth equity arm, in 2026, which valued the company at approximately $1.3 billion and made it an AI-infrastructure unicorn; Sacra estimated the company crossed roughly $50 million in annualized revenue in March 2026, up from about $19 million at the end of 2025. Pricing is primarily usage-based: OpenRouter offers a free tier with access to 25-plus free models and roughly 50 requests per day, a pay-as-you-go tier with no minimum spend where customers pay the underlying model's list price plus a 5.5% platform fee, with volume discounts available, and an Enterprise tier offering SSO, contractual SLAs, dedicated rate limits, and up to $200,000 of monthly inference at list price with no markup before the standard fee applies above that threshold. OpenRouter's target audience is AI application developers, from solo builders to enterprise engineering teams, who need to run, test, or fall back across multiple LLM providers without managing separate contracts and billing relationships with each one. Its closest competitors include direct provider APIs from OpenAI, Anthropic, and Google, other LLM gateway or routing tools such as Portkey and LiteLLM, and cloud-hosted model marketplaces like Amazon Bedrock and Google Vertex AI, with OpenRouter differentiated by its breadth of models, transparent per-model pricing comparison, and simple unified billing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54b33467-c0e1-45e4-b29f-69b5ce8ea2dd';

