INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Independent Testing and Assessment Engine$q$, $q$A dedicated exam engine supports timed, randomized, proctorable high-stakes tests separately from lightweight self-assessment quizzes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Integrated Video Conferencing$q$, $q$Built-in BigBlueButton support enables live webinars and video classes directly inside a course.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$SCORM, xAPI, and QTI Course Authoring$q$, $q$Courses can import and export standard e-learning content formats for interoperability with other systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Document Collaboration$q$, $q$OnlyOffice integration allows learners and instructors to co-edit documents inside a course workspace.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Enterprise Identity Integration$q$, $q$LDAP, Active Directory, OAuth2, and Shibboleth support institutional single sign-on at scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Multi-language Interface$q$, $q$The platform interface and course content can be delivered in roughly 20 languages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Calendar and Attendance Tracking$q$, $q$Built-in scheduling tools handle instructor calendars, room booking, and attendance records.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Quality Management Tools$q$, $q$Integrated evaluation and survey tools support institutional accreditation and quality-assurance processes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Free and open source with full source code access$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Built-in exam-grade testing environment suitable for high-stakes assessments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Strong data sovereignty for EU and Swiss institutions via self-hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Deep enterprise identity integration, including LDAP and SSO$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Actively maintained with a long-running institutional user base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Smaller plugin ecosystem than Moodle$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Self-hosting requires dedicated IT and Java expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Documentation and community discussion skew toward German language$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Managed hosting pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Interface feels more utilitarian than newer consumer-style LMS platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Is OpenOLAT free to use?$q$, $q$Yes. OpenOLAT is open-source software that can be downloaded and self-hosted at no licensing cost. Organizations that want managed hosting or support pay frentix, the company behind the project, for those services.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Who maintains OpenOLAT?$q$, $q$OpenOLAT is developed and maintained by frentix GmbH, a Zurich, Switzerland-based company founded in 2006 by one of the original OLAT developers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$What is the difference between OLAT and OpenOLAT?$q$, $q$OLAT was the original learning management system built by the University of Zurich. OpenOLAT is a fork created in 2011 by frentix after the university restructured its own development process.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Can OpenOLAT be used for high-stakes exams?$q$, $q$Yes. OpenOLAT includes an independent testing environment designed for timed, randomized, high-stakes examinations in addition to informal self-assessment quizzes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Does OpenOLAT support SCORM content?$q$, $q$Yes, OpenOLAT supports SCORM, xAPI, and IMS QTI standards for importing and exporting course content.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$How many languages does OpenOLAT support?$q$, $q$The interface and course content can be delivered in roughly 20 languages, reflecting its use across multilingual European institutions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$How does OpenOLAT compare to Moodle?$q$, $q$OpenOLAT is generally considered more lightweight to administer with a more opinionated architecture, while Moodle has a larger global plugin ecosystem and community.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$University online course delivery and exams$q$, $q$Universities use OpenOLAT to run online and blended courses along with proctored, high-stakes examinations.$q$, $q$Higher education institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Corporate training and compliance certification$q$, $q$Enterprises use OpenOLAT to deliver employee training programs and track completion for compliance certification.$q$, $q$Corporate learning and development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Government and public-sector training programs$q$, $q$Public institutions use OpenOLAT's self-hosting capability to run training programs while keeping data within national or EU borders.$q$, $q$Government agencies and public organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source platform","Self-hosted deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$Managed Hosting and Support$q$, $q$Custom, quoted by frentix$q$, $q$Contract-based$q$, NULL, $q$["Hosting management","Technical support","Training and customization"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenOLAT is a web-based, open-source learning management system used for teaching, assessment, and communication at universities, vocational schools, enterprises, and government institutions. The name stands for Open Online Learning And Training, and the project was forked in 2011 from the University of Zurich's original OLAT platform by frentix GmbH, a Zurich-based company co-founded by one of OLAT's original developers.$q$, $q$Unlike many open-source LMS platforms that started as hobby or community projects, OpenOLAT was built from day one by a company with deep institutional e-learning experience, and that heritage shows in its exam-grade testing engine, enterprise identity integrations, and focus on scalability for large student and employee populations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenOLAT's testing environment is built to run both low-stakes self-assessments and high-stakes, timed, randomized examinations independently of the course-authoring tools, which is a common gap in lighter-weight LMS platforms. It integrates BigBlueButton for live video conferencing and webinars, supports YouTube-style video hosting with embedded interactive questions, and includes OnlyOffice-based document collaboration for group work.$q$, $q$On the administration side, OpenOLAT connects to LDAP, Active Directory, OAuth2, and Shibboleth for single sign-on, supports SCORM, xAPI, and IMS QTI content standards, and includes calendar, attendance tracking, and quality-management/evaluation tools suited to accredited education providers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2781d6d-0be8-4b83-b404-3a5b91254b15', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenOLAT itself is free and open source: any organization can download, install, and run it on its own servers at no licensing cost. For institutions that prefer not to manage their own infrastructure, frentix offers managed hosting ranging from full operational management to technical support only.$q$, $q$Because hosting and support needs vary widely by institution size and requirements, frentix does not publish fixed price tiers; pricing is quoted individually after a scoping conversation, similar to how most other institution-grade open-source LMS vendors operate.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Member and Household Management$q$, $q$Tracks CSA member records, households, and contact information in one system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Share and Subscription Planning$q$, $q$Manages harvest-share sizes, subscription types, and seasonal planning for members.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Delivery Point and Route Scheduling$q$, $q$Coordinates delivery locations, pickup points, and distribution schedules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Automated Invoicing$q$, $q$Generates and tracks invoices for member shares and subscriptions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Absence and Vacation Management$q$, $q$Lets members register absences so deliveries and shares can be adjusted accordingly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Bulk Email Communication$q$, $q$Sends group emails and updates to members directly from the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Multilingual Interface$q$, $q$Available in eight languages to support CSA groups across several European countries.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Completely free and open source under the AGPL v3 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Purpose-built specifically for CSA and share-farming workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Community co-financing model keeps development aligned with real farm needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Full data ownership through self-hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Actively used by CSA groups across multiple European countries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$No formal company means limited dedicated commercial support$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Requires technical setup or community help to host and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Small user base of roughly fifteen known CSAs limits the surrounding ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Documentation is primarily in German$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Feature development pace depends on community co-financing availability$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$What is OpenOlitor used for?$q$, $q$OpenOlitor is used by Community Supported Agriculture (CSA) groups to manage members, plan harvest shares, schedule deliveries, and handle invoicing and communication.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Is OpenOlitor free to use?$q$, $q$Yes. OpenOlitor is free, open-source software released under the AGPL v3 license. There is no vendor charging subscription fees, though hosting and support may involve community-arranged costs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Who develops OpenOlitor?$q$, $q$OpenOlitor is maintained by an international, informally-organized team of more than ten contributors based in Switzerland, Germany, Austria, and Italy, with support from the Bern-based cooperative Tegonal GmbH.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$What license is OpenOlitor released under?$q$, $q$OpenOlitor was released under GPL v3 until April 2018 and has been released under AGPL v3 since then.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$How many organizations use OpenOlitor?$q$, $q$OpenOlitor is used by roughly fifteen CSA organizations across Switzerland and Germany.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$What languages is OpenOlitor available in?$q$, $q$OpenOlitor is translated into eight languages, including German, French, Italian, and English.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Do I need technical skills to run OpenOlitor?$q$, $q$Yes, some technical knowledge or community assistance is typically needed to deploy and host an OpenOlitor instance, since there is no commercial vendor offering turnkey setup.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$CSA farm managing weekly harvest shares$q$, $q$A farm uses OpenOlitor to plan harvest shares, schedule deliveries, and invoice members each season.$q$, $q$CSA farm operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Food cooperative coordinating deliveries$q$, $q$A food cooperative uses OpenOlitor to manage multiple delivery points and member communication.$q$, $q$Food cooperative coordinators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Volunteer-run share network$q$, $q$A volunteer-run share network uses OpenOlitor to track member absences and adjust deliveries accordingly.$q$, $q$Volunteer coordinators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Self-Hosted Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","AGPL v3 license","Self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$Community-Financed Feature Development$q$, $q$Variable, by contribution$q$, $q$Project-based$q$, NULL, $q$["Co-funded by participating CSA groups","Prioritized by community needs"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenOlitor is an open-source administration platform built specifically for Community Supported Agriculture (CSA) groups, where consumers subscribe in advance to a share of a farm's harvest. The project has been developed since around 2014 by an international, informally-organized team based in Switzerland, Germany, Austria, and Italy, with early funding co-provided by Switzerland's Federal Office for Agriculture and the Bern-based software cooperative Tegonal GmbH.$q$, $q$Rather than being sold by a company, OpenOlitor is sustained through a 'Community Supported Software' model: the CSA organizations that rely on the tool contribute financially and organizationally to fund ongoing development, echoing the same solidarity-based funding logic used in the CSA farming model itself.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenOlitor handles the day-to-day operations of running a share-based farm: member and household records, harvest-share and subscription planning, delivery-point and route scheduling, absence and vacation handling, automated invoicing, and bulk email communication with members.$q$, $q$The platform is translated into eight languages and released under the AGPL v3 open-source license, giving CSA groups full access to the source code and the ability to self-host their data rather than depend on a proprietary vendor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0070da27-b0bd-4679-add1-4cfaeb297161', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenOlitor has no traditional pricing plans. The software is free to download and self-host under its open-source license, and there is no company charging subscription fees.$q$, $q$CSA groups that adopt it typically need to arrange their own hosting, either self-managed or through community volunteers and Tegonal GmbH, and larger new features are generally funded collectively by the participating CSA organizations rather than purchased individually.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Shared Business Phone Numbers$q$, $q$Multiple team members can call, text, and manage conversations from one shared business number and inbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$AI Call Summaries and Transcripts$q$, $q$Calls are automatically transcribed and summarized for quick review without replaying the full recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Sona AI Agent$q$, $q$An AI voice agent can answer routine incoming calls and handle basic requests automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Unlimited US and Canada Calling and Texting$q$, $q$All plans include unlimited domestic calling and messaging within the US and Canada.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$HubSpot and Salesforce Integrations$q$, $q$Native CRM integrations sync call and text activity directly into sales and support workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Auto-Attendant Phone Menus$q$, $q$Configurable phone menus route incoming calls to the right team member or department.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Automatic Call Recording$q$, $q$Calls are recorded automatically on Business and Scale plans for training and quality review.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Group Calling and Call Transfers$q$, $q$Teams can ring multiple people at once or transfer an active call to a colleague.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Modern shared-inbox model makes team texting and calling collaborative$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Strong AI features, including summaries, transcripts, and an AI agent, built into core plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Fast setup with no phone hardware required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Native CRM integrations with HubSpot and Salesforce$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Transparent per-user pricing with a free trial$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Recent rebrand to Quo has caused some confusion among existing customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Higher-tier AI features require the Business or Scale plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$International calling coverage is more limited than legacy telecom providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$No permanent free plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Advanced call-center features trail dedicated contact-center software$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Is OpenPhone still called OpenPhone?$q$, $q$The company rebranded from OpenPhone to Quo in late 2025. It is the same company and product, now marketed under the Quo name at quo.com.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$How much does OpenPhone cost?$q$, $q$Plans range from $15/user/month (Starter, billed annually) up to $35/user/month (Scale, billed annually), with higher month-to-month pricing available on all tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Can multiple people share one OpenPhone number?$q$, $q$Yes. OpenPhone's core feature is a shared business number and shared inbox that multiple team members can use together.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Does OpenPhone offer a free trial?$q$, $q$Yes, all plans include a 7-day free trial that does not require a credit card.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$What integrations does OpenPhone support?$q$, $q$OpenPhone integrates natively with HubSpot and Salesforce, among other tools, for sales and support teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Who founded OpenPhone?$q$, $q$OpenPhone was founded in 2018 by Daryna Kulya and Mahyar Raissi and is headquartered in San Francisco.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Who is OpenPhone best for?$q$, $q$OpenPhone is best suited to small businesses, startups, and sales or support teams that want a modern, collaborative phone system without traditional PBX hardware.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Startup sales team phone line$q$, $q$A sales team shares a business number to call and text leads while syncing activity to their CRM.$q$, $q$Startup sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Customer support shared inbox$q$, $q$A support team uses a shared number and inbox to manage customer calls and texts collaboratively.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Distributed remote team business line$q$, $q$A remote team gives every employee a professional business number without provisioning physical phones.$q$, $q$Small business owners and remote teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Starter$q$, $q$$15/user/month (annual) or $19/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["One phone number per user","Unlimited US/Canada calling and messaging","Voicemail transcripts","Sona AI agent with free credits","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Business$q$, $q$$23/user/month (annual) or $33/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Starter","AI call summaries and transcripts","Group calling and call transfers","HubSpot and Salesforce integrations","Phone menus and automatic call recording"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Scale$q$, $q$$35/user/month (annual) or $47/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Business","AI call tags","Dedicated onboarding support","Priority live chat and email support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenPhone is a cloud-based business phone system founded in 2018 by Daryna Kulya and Mahyar Raissi and headquartered in San Francisco. It was built as a modern replacement for legacy desk phones and PBX systems, letting small teams set up business phone numbers that work through an app rather than physical hardware.$q$, $q$In late 2025 the company rebranded to Quo, expanding its focus toward AI-powered business communication while retaining the same underlying phone-system product. The two names describe the same company and platform, with existing OpenPhone customers migrated to the Quo brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's signature feature is the shared phone number and shared inbox, which lets multiple team members call, text, and see conversation history from one business line, much like a shared team email inbox. It also includes AI call summaries and transcripts, an AI voice agent (Sona) that can handle routine incoming calls, and automatic call recording.$q$, $q$Additional features include auto-attendant phone menus, group calling and call transfers, voicemail transcription, and native integrations with HubSpot and Salesforce, making it a common choice for sales and customer support teams that need calling built into their CRM workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenPhone uses per-user, tiered subscription pricing with a discount for annual billing. Starter costs $15/user/month billed annually (or $19/user/month billed monthly) and covers core calling, texting, and voicemail transcription.$q$, $q$Business costs $23/user/month annually (or $33 monthly) and adds AI call summaries, CRM integrations, and phone menus, while Scale costs $35/user/month annually (or $47 monthly) and adds AI call tagging and dedicated onboarding support. All plans include a 7-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Interactive Gantt Chart Scheduling$q$, $q$Visual, drag-and-drop scheduling with dependencies for classic project timelines.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Agile and Scrum or Kanban Boards$q$, $q$Backlogs, sprint planning, and Kanban boards support agile software development workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Time and Cost Tracking$q$, $q$Built-in time logging and budget tracking tied directly to project tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$BIM Integration$q$, $q$Native Building Information Modeling support for construction and engineering scheduling.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Wiki and Meeting Management$q$, $q$Project wikis and structured meeting agendas keep documentation and decisions centralized.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Budgeting and Reporting$q$, $q$Cost planning and reporting tools track budgets against project progress.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$On-Premises or Cloud Hosting$q$, $q$Deployable fully on-premises, in a private cloud, or on OpenProject's hosted cloud.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Roadmap and Backlog Planning$q$, $q$Long-term roadmap views connect high-level plans to sprint-level backlogs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Free, fully-featured open-source Community edition$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Can be fully self-hosted for data sovereignty and compliance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Native BIM support unusual among mainstream project management tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Strong fit for government and EU-regulated organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Combines classic Gantt planning with agile Scrum and Kanban in one tool$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Interface feels less polished than modern SaaS competitors like Asana or Monday.com$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Paid tiers require a 25-user minimum$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Premium and Corporate tiers require large minimum user counts of 100 to 250$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Self-hosting requires IT resources to maintain$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Smaller third-party integration ecosystem than Jira$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Is OpenProject really free?$q$, $q$Yes, the Community edition is free and open source under GPLv3 and can be self-hosted with no user limit, though support is community-based rather than commercial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Can OpenProject be self-hosted?$q$, $q$Yes. OpenProject can run fully on-premises, in a private cloud, or on OpenProject's own hosted cloud service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Does OpenProject support BIM?$q$, $q$Yes, OpenProject includes native Building Information Modeling support, which can be added to any paid plan for roughly EUR 1 per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$What is the minimum number of users for paid plans?$q$, $q$Basic and Professional plans require a 25-user minimum, Premium requires 100 users, and Corporate requires 250 users.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$How does OpenProject compare to Jira?$q$, $q$OpenProject offers a free, self-hostable open-source option that Jira does not, but has a smaller third-party integration ecosystem than Jira.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Who develops OpenProject?$q$, $q$OpenProject is developed by OpenProject GmbH, headquartered in Berlin, Germany.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Does OpenProject offer a free trial for paid plans?$q$, $q$OpenProject offers trial access to its paid cloud plans; exact trial terms should be confirmed on openproject.org since they can change.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Software team running agile sprints$q$, $q$A development team uses Scrum boards and backlogs to plan and track sprints.$q$, $q$Agile software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Construction firm needing BIM scheduling$q$, $q$An engineering firm uses OpenProject's BIM integration alongside Gantt charts to schedule construction phases.$q$, $q$Construction and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Government agency needing self-hosted project management$q$, $q$A public-sector agency self-hosts OpenProject to keep project data within national infrastructure for compliance.$q$, $q$Government and public-sector organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited self-hosted use","GPLv3 open source","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Basic$q$, $q$About EUR 5.95/user/month$q$, $q$Monthly or annual (25-user minimum)$q$, NULL, $q$["All Community features","Basic enterprise add-ons","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Professional$q$, $q$About EUR 10.95/user/month$q$, $q$Monthly or annual (25-user minimum)$q$, NULL, $q$["All Basic features","Professional enterprise add-ons","Phone support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Premium$q$, $q$About EUR 15.95/user/month$q$, $q$Annual or multi-year (100-user minimum)$q$, NULL, $q$["All Professional features","Premium add-ons","Remote-hands support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$Corporate$q$, $q$Custom pricing$q$, $q$Annual or multi-year (250-user minimum)$q$, NULL, $q$["All Premium features","openDesk integration","Dedicated support engineer"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenProject is an open-source project management platform headquartered in Berlin, Germany, tracing back to a 2012 fork of the earlier ChiliProject tool. It has grown into one of the most widely deployed self-hostable project management systems, particularly popular with government agencies, universities, and EU-based enterprises that need to keep project data on their own infrastructure.$q$, $q$Unlike SaaS-only competitors, OpenProject can run entirely on-premises, in a customer's own cloud, or on OpenProject's hosted cloud, giving IT and public-sector buyers a compliant middle ground between free open-source tools and closed commercial SaaS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenProject combines classic project planning with agile workflows: interactive Gantt chart scheduling sits alongside Scrum and Kanban boards, backlog and sprint planning, and roadmap views, letting teams mix waterfall and agile methods in the same workspace.$q$, $q$It also includes time and cost tracking, a wiki, meeting management, budgeting tools, and native Building Information Modeling (BIM) support, an uncommon feature among general-purpose project management tools that makes it popular with construction and engineering teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c81a24e-2f8d-479b-aeeb-638429dd55ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community edition is free, open source under GPLv3, and can be self-hosted with no user limit, though support is community-based. Paid cloud or on-premises plans start with Basic at about EUR 5.95/user/month, Professional at about EUR 10.95/user/month, and Premium at about EUR 15.95/user/month, each requiring minimum user counts of 25 to 100.$q$, $q$A custom-quoted Corporate tier is available for organizations with 250 or more users, adding a dedicated support engineer and integration with Germany's openDesk suite. BIM features can be added to any paid plan for roughly EUR 1 per user per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Multi-Format Document Support$q$, $q$Reads EPUB, PDF, DOCX, TXT, and Markdown files in one interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Synchronized Word-Level Highlighting$q$, $q$Highlights the exact word being narrated using ONNX Whisper-based alignment, even in complex PDF layouts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Multiple Text-to-Speech Provider Options$q$, $q$Supports hosted providers (OpenAI, Replicate, DeepInfra) or self-hosted offline engines (Kokoro, KittenTTS, Orpheus).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Audiobook Export$q$, $q$Generates a downloadable narrated audio file from any supported document.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Self-Hostable Docker Deployment$q$, $q$Runs via Docker on amd64 or arm64 servers with S3-compatible storage.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Built-in Authentication and Migrations$q$, $q$Includes built-in user authentication and automatic database migrations on startup.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Free and fully open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Supports both hosted and fully self-hosted, offline TTS engines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Handles multiple document formats in one tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Active GitHub project with hundreds of stars and ongoing updates$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Docker-based deployment is straightforward for self-hosters$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Requires users to bring their own API keys or run their own TTS server for best quality$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Maintained by an individual developer rather than a company, so support is community-based$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$No official cloud-hosted version with a support agreement$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Setup requires some technical comfort with Docker, storage, and databases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Feature set and stability may change quickly as an early-stage independent project$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Is OpenReader free?$q$, $q$Yes, OpenReader is free and open source under the MIT license. The only potential costs come from the text-to-speech provider you choose to connect.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Who makes OpenReader?$q$, $q$OpenReader is built and maintained by independent developer Richard Roberson (GitHub handle richardr1126), first published in January 2025.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$What file formats does OpenReader support?$q$, $q$OpenReader supports EPUB, PDF, DOCX, TXT, and Markdown documents.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Can OpenReader run fully offline?$q$, $q$Yes, OpenReader can be configured with self-hosted, offline text-to-speech engines like Kokoro, KittenTTS, or Orpheus.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Does OpenReader export audiobooks?$q$, $q$Yes, OpenReader can generate a full downloadable audiobook export from any supported document.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Do I need an OpenAI account to use OpenReader?$q$, $q$No, OpenAI is one optional text-to-speech provider; you can also use Replicate, DeepInfra, or a self-hosted TTS engine.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Is there a hosted version of OpenReader I can just sign up for?$q$, $q$There is a public demo at openreader.richardr.dev, but there is no commercial SaaS version with a support agreement; the intended use is self-hosting.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Narrated reading for accessibility$q$, $q$Individuals use OpenReader to turn PDFs and ebooks into narrated, highlighted audio for easier reading.$q$, $q$Readers with visual impairment or dyslexia$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Self-hosted audiobook creation$q$, $q$Privacy-conscious users self-host OpenReader to convert their personal document library into audiobooks without a subscription service.$q$, $q$Privacy-conscious self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Custom TTS reading experiences$q$, $q$Developers use OpenReader's open-source codebase as a foundation for building custom read-along applications.$q$, $q$Developers and hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT license","Full source code access","Requires own TTS provider or self-hosted TTS engine"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$Hosted Demo$q$, $q$Free to try$q$, $q$N/A$q$, NULL, $q$["Public demo at openreader.richardr.dev","Limited to demonstration use, not a commercial SaaS plan"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenReader is an open-source, self-hosted read-along document reader created by independent developer Richard Roberson and first published on GitHub in January 2025. It is not a company or commercial product; it is a solo-maintained open-source project released under the MIT license, with a public demo hosted at openreader.richardr.dev.$q$, $q$The tool is designed for people who want a synchronized narration experience, audio read aloud with word-level highlighting, for their own documents, without depending on a subscription audiobook service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenReader supports EPUB, PDF, DOCX, TXT, and Markdown files, using layout-aware parsing and ONNX Whisper-based alignment so that highlighting follows the true reading order even in complex, multi-column PDFs. Users can generate a full audiobook export from any supported document.$q$, $q$Text-to-speech can be powered by hosted providers such as OpenAI, Replicate, or DeepInfra, or by fully self-hosted, offline engines like Kokoro, KittenTTS, and Orpheus, giving users control over cost and data privacy. Deployment is via Docker, with support for S3-compatible storage and SQLite or Postgres databases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f47d23ca-0f56-4a32-b7b9-20cfb7465b77', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenReader itself is completely free and open source under the MIT license; there is no subscription or license fee for the software. Costs, if any, come only from the text-to-speech provider a user chooses to connect, such as per-request API charges from OpenAI, Replicate, or DeepInfra.$q$, $q$Users who self-host an offline TTS engine like Kokoro can run OpenReader with no ongoing usage costs at all, aside from their own server hosting expenses.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Asset-Centric Data Model$q$, $q$Users define custom asset types and track their attributes and history over time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Multi-Protocol Device Support$q$, $q$Built-in support for MQTT, ModBus, KNX, Bluetooth, LoRaWAN, SNMP, Velbus, and more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Visual Flow Editor and Rules Engine$q$, $q$Automation can be built with simple rules, a visual flow editor, or Groovy scripting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Built-in Dashboard Builder$q$, $q$Live and historical data visualization dashboards without extra tooling.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Maps and Geofencing$q$, $q$Location tracking with customizable map layers and geofence-triggered alerts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Unified REST API and WebSockets$q$, $q$Every asset and attribute is automatically exposed for external system integration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Multi-Tenant Realm Isolation$q$, $q$Logical separation of data and users across different organizations or projects.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Keycloak-Powered Identity Management$q$, $q$Enterprise-grade OAuth2 and OpenID Connect authentication built in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Fully open source with no paywalled enterprise features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Broad native protocol support reduces custom integration work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$No per-device licensing fees for self-hosted deployments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Flexible automation options, from simple rules to full scripting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Bootstrapped, stable company focused on long-term open-source commitment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$No published SaaS pricing; managed hosting and support are quoted per project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Requires self-hosting or a paid managed instance to run in production$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Smaller company means slower feature velocity than venture-funded IoT platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Steeper learning curve for teams new to asset-based IoT modeling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Smaller community and ecosystem than some larger IoT platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Is OpenRemote free to use?$q$, $q$Yes, the core OpenRemote platform is free and open source for self-hosted use. Managed hosting and professional services are paid and quoted per project.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Who founded OpenRemote?$q$, $q$OpenRemote was founded in 2008 by Marc Fleury, the creator of the JBoss open-source Java application server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$What protocols does OpenRemote support?$q$, $q$OpenRemote has built-in support for HTTP, MQTT, ModBus, KNX, Bluetooth, LoRaWAN, SNMP, Velbus, TCP, UDP, and serial connections.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Is OpenRemote suitable for smart home use?$q$, $q$OpenRemote started as a smart-home project but pivoted around 2016 to focus on enterprise and OEM IoT device management rather than consumer smart homes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Does OpenRemote offer managed hosting?$q$, $q$Yes, OpenRemote offers managed cloud hosting and professional configuration services on a paid, quoted basis.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$What license is OpenRemote released under?$q$, $q$OpenRemote's full stack, including the backend, rules engine, and console, is published as open-source software on GitHub.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Who is OpenRemote best for?$q$, $q$OpenRemote is best suited to professional IoT integrators, OEMs, and enterprise teams managing complex, multi-protocol asset ecosystems in areas like smart buildings and energy management.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Smart building energy management$q$, $q$Facilities teams use OpenRemote to monitor and automate energy usage across building systems.$q$, $q$Facilities and energy managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Industrial IoT asset monitoring$q$, $q$Industrial integrators use OpenRemote to track machine and sensor data across a manufacturing site.$q$, $q$Industrial integrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Smart city infrastructure monitoring$q$, $q$Municipalities use OpenRemote to monitor and manage connected city infrastructure like lighting and sensors.$q$, $q$Municipalities and city IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Open Source Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full platform access","Self-hosted deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$Managed Hosting and Professional Services$q$, $q$Custom, quoted per project$q$, $q$Contract-based$q$, NULL, $q$["Managed cloud hosting","Custom configuration and integration","Ongoing support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenRemote is a 100% open-source IoT platform originally founded in 2008 by Marc Fleury, the creator of the JBoss Java application server, initially as a smart-home automation project. Around 2016 the project pivoted to focus on enterprise and OEM IoT device management rather than consumer smart homes.$q$, $q$The company, OpenRemote B.V., is headquartered in Eindhoven, the Netherlands, and remains privately held and bootstrapped, funding development through client contracts for hosting, customization, and professional services rather than venture capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenRemote uses an asset-centric data model where users define custom asset types, buildings, sensors, vehicles, or energy devices, and track their attributes over time. It includes native support for a wide range of IoT protocols, including MQTT, ModBus, KNX, Bluetooth, LoRaWAN, SNMP, and Velbus.$q$, $q$Automation can be configured with simple When-Then rules, a visual Flow Editor for data pipelines, or Groovy scripting for advanced logic. Every asset is automatically exposed via a unified REST API and WebSockets, and the platform includes a built-in dashboard builder, map-based geofencing, and Keycloak-powered enterprise identity management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86bb955c-8712-45a0-8f45-aeab54c99a6f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenRemote's core platform is free and open source with no licensing fees for self-hosted use; the full stack is available on GitHub with no paywalled enterprise edition.$q$, $q$Organizations that prefer not to run and maintain their own infrastructure can pay OpenRemote for managed cloud hosting, custom configuration, and integration development, with pricing quoted individually per project rather than published as fixed tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Session Replay with Pixel-Accurate Reconstruction$q$, $q$Records and replays user sessions exactly as they happened in the browser or app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Developer Tools$q$, $q$Captures console logs, network requests, and JavaScript errors alongside the replay.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Framework State Tracking$q$, $q$Captures Redux, Vuex, Pinia, and GraphQL state changes for deeper debugging.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Co-Browsing$q$, $q$Lets support agents see and interact with a live user session in real time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Product Analytics$q$, $q$Includes funnels, heatmaps, and user-flow analysis alongside session replay.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Spot Bug and Feedback Capture$q$, $q$A lightweight tool for capturing and sharing bug reports and feedback.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Self-Hosted or BYOC Deployment$q$, $q$Can run fully on customer infrastructure or in a bring-your-own-cloud setup.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$MCP Server for AI Debugging$q$, $q$Connects session data to AI coding and debugging workflows via an MCP server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Fully open source and self-hostable at zero licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Combines session replay and developer debugging tools in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Strong data-privacy story for regulated or security-conscious teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Deep framework-level state capture beyond basic screen recording$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Backed by Y Combinator with a focused, developer-first roadmap$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Self-hosting requires DevOps effort to run and scale the stack$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Managed Dedicated plan pricing is higher than some SaaS competitors' entry tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Smaller company and community than LogRocket, Hotjar, or FullStory$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Product analytics features are less mature than dedicated analytics tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Is OpenReplay really free?$q$, $q$Yes, the Open-Source edition is free to self-host. Paid tiers exist for customers who want a managed cloud instance or enterprise-scale support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$What is the difference between OpenReplay and Asayer?$q$, $q$Asayer was the original closed-source SaaS product; the company pivoted to an open-source model in 2020 and rebranded the product as OpenReplay.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Can OpenReplay be self-hosted?$q$, $q$Yes, self-hosting is the core of OpenReplay's Open-Source edition, and it is also supported in a bring-your-own-cloud (BYOC) configuration on the Dedicated plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$How does OpenReplay compare to LogRocket and Hotjar?$q$, $q$OpenReplay's main differentiator is that it can be fully self-hosted at no licensing cost, while LogRocket and Hotjar are closed-source SaaS-only products.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$What does the Dedicated plan cost?$q$, $q$The Dedicated managed cloud plan starts around $199 per month, billed hourly at roughly $0.276 per hour.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Does OpenReplay support mobile apps?$q$, $q$OpenReplay is primarily built for web applications; mobile session capture support should be confirmed against current documentation for specific frameworks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Does OpenReplay capture Redux or GraphQL state?$q$, $q$Yes, OpenReplay captures framework-level state including Redux, Vuex, Pinia, and GraphQL queries alongside the session replay.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Engineering teams debugging production errors$q$, $q$Developers replay user sessions alongside console logs and errors to reproduce and fix bugs faster.$q$, $q$Frontend and full-stack engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Data-sensitive companies needing self-hosted analytics$q$, $q$Regulated organizations self-host OpenReplay to keep user session data entirely on their own infrastructure.$q$, $q$Regulated industries and security-conscious teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Customer support co-browsing$q$, $q$Support teams use co-browsing to see and help resolve a customer's live session in real time.$q$, $q$Customer support and success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Open-Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Unlimited usage on own infrastructure","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Dedicated$q$, $q$From $199/month (billed hourly, about $0.276/hr)$q$, $q$Hourly/monthly$q$, NULL, $q$["Managed cloud or BYOC deployment","SSO/SAML","Dedicated support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Multi-year contract$q$, NULL, $q$["Self-hosted at scale","SAML/SCIM provisioning","Audit logging and custom SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenReplay is an open-source session replay and developer debugging platform built by Asayer, Inc., a Paris-based company founded in 2018 by CEO Mehdi Osman and backed by Y Combinator. The company originally operated as a closed-source SaaS tool named Asayer before pivoting the entire product to an open-source model in 2020 and rebranding as OpenReplay.$q$, $q$The pivot to open source was a deliberate strategy to differentiate from closed-source incumbents like FullStory, Hotjar, and LogRocket, letting engineering teams self-host the full stack and keep user session data entirely on their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenReplay records everything a user does in a web or mobile app, clicks, scrolls, network requests, console logs, JavaScript errors, and framework-level state (Redux, Vuex, Pinia, GraphQL), then reconstructs it as a pixel-accurate replay synchronized with more than 40 performance metrics, combining session replay and developer debugging in one tool.$q$, $q$It also includes co-browsing for live customer support sessions, a lightweight bug and feedback capture tool called Spot, product analytics such as funnels and heatmaps, and an MCP server for connecting session data into AI-assisted debugging workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79eaac2-65bc-4cc5-9c8f-74c78142ea6b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Open-Source edition is completely free to self-host, with the customer responsible for their own infrastructure, scaling, and backups. The Dedicated tier is a managed cloud instance starting around $199 per month, billed hourly at roughly $0.276 per hour, and can run in OpenReplay's cloud or the customer's own cloud environment.$q$, $q$An Enterprise tier is available for large-scale self-hosted deployments, with custom pricing, SAML/SCIM provisioning, audit logging, and multi-year contracts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Unified API for 400+ Models$q$, $q$Access models from over 70 providers through a single API endpoint and API key.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Automatic Failover and Provider Routing$q$, $q$Requests automatically route to the best-available provider and fall back during outages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Real-Time Price and Latency Comparison$q$, $q$Compare pricing, latency, and throughput across providers offering the same model.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Free Tier with 25+ Free Models$q$, $q$A no-cost tier gives limited daily access to a selection of free models.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Pay-As-You-Go Billing$q$, $q$Usage-based pricing with no minimum spend, billed at provider cost plus a platform fee.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Enterprise SSO and SLAs$q$, $q$Enterprise plans add single sign-on, contractual SLAs, and dedicated rate limits.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Single API Key for Multiple Providers$q$, $q$One API key replaces separate integrations with each individual model provider.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Flexible Payment Options$q$, $q$Supports credit card, cryptocurrency, and other payment methods for usage billing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Access to hundreds of models through one integration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Automatic fallback improves reliability during provider outages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Transparent, comparable pricing across providers for the same model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$No minimum spend on pay-as-you-go usage$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Fast-growing, well-funded company with strong momentum$q$, 4);
