INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Reliant on third-party providers' uptime and model availability$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$What is OpenRouter?$q$, $q$OpenRouter is a unified API that lets developers access more than 400 large language models from over 70 providers through a single API key.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$How much does OpenRouter cost?$q$, $q$OpenRouter offers a free tier, then charges pay-as-you-go usage at the underlying model's list price plus a 5.5% platform fee, with volume discounts on Enterprise plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Does OpenRouter have a free tier?$q$, $q$Yes, OpenRouter offers a free tier with access to more than 25 free models and roughly 50 requests per day.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$How many models does OpenRouter support?$q$, $q$OpenRouter supports more than 400 models from over 70 providers, including OpenAI, Anthropic, Google, Meta, Mistral, and DeepSeek.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Who founded OpenRouter?$q$, $q$OpenRouter was founded in 2023 by Alex Atallah, previously co-founder and CEO of the NFT marketplace OpenSea.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$How does OpenRouter compare to using OpenAI or Anthropic directly?$q$, $q$OpenRouter adds a platform fee on top of direct provider pricing but offers automatic failover, unified billing, and access to many providers through one integration.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Is OpenRouter suitable for enterprise use?$q$, $q$Yes, OpenRouter offers an Enterprise tier with SSO, contractual SLAs, dedicated rate limits, and volume-based fee discounts.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$AI app developer needing multi-model flexibility$q$, $q$A developer builds an app that can switch between AI models and providers without rewriting integration code.$q$, $q$Startup and indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Enterprise needing provider redundancy and SLAs$q$, $q$An enterprise engineering team uses OpenRouter for automatic failover and contractual reliability guarantees across providers.$q$, $q$Enterprise engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Researchers comparing model performance$q$, $q$Researchers and hobbyists use OpenRouter to test and compare many models' outputs, cost, and latency in one place.$q$, $q$AI researchers and hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["25+ free models","About 50 requests per day","Access to chat and API"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Pay-As-You-Go$q$, $q$Provider cost plus 5.5% platform fee$q$, $q$Usage-based, no minimum spend$q$, NULL, $q$["Access to 400+ models","Real-time price and latency comparison","Credit card and crypto payment options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contract-based$q$, NULL, $q$["SSO and contractual SLAs","Dedicated rate limits","Volume-based fee discounts"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenRouter is a unified API and routing layer for large language models, founded in 2023 by Alex Atallah, previously co-founder and CEO of the NFT marketplace OpenSea, and headquartered in New York City. It gives developers a single API endpoint and API key to access more than 400 AI models from over 70 providers, including OpenAI, Anthropic, Google, Meta, Mistral, and DeepSeek.$q$, $q$The company has grown quickly, raising a $113 million Series B led by CapitalG, Alphabet's growth equity arm, in 2026 at an approximate $1.3 billion valuation, following an earlier $12.5 million seed round from Andreessen Horowitz and a $28 million Series A led by Menlo Ventures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenRouter automatically routes requests to the best-available provider for a chosen model and falls back to alternate providers during outages, improving reliability compared with calling a single provider directly. Developers can compare real-time pricing, latency, and throughput across providers offering the same model.$q$, $q$The platform gives access to 400-plus models through one integration and one API key, removing the need to manage separate SDKs, billing relationships, and rate limits with each individual AI provider.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54b33467-c0e1-45e4-b29f-69b5ce8ea2dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenRouter offers a free tier with access to more than 25 free models and roughly 50 requests per day. Its main pricing model is pay-as-you-go, with no minimum spend, where customers pay the underlying model provider's list price plus a 5.5% platform fee.$q$, $q$An Enterprise tier adds SSO, contractual SLAs, dedicated rate limits, and volume-based fee discounts, including up to $200,000 of monthly inference at list price with no markup before the standard fee applies above that threshold.$q$]::text[], 2);
